using UnityEngine;

public class CameraFollow : MonoBehaviour
{
    [SerializeField] private Transform target;
    [SerializeField] private Vector3 offset = new Vector3(0f, 5f, -10f);
    [SerializeField] private float smoothSpeed = 5f;

    // LateUpdate runs after all Update() calls,
    // so the camera reacts to the player's FINAL position each frame
    void LateUpdate()
    {
        if (target == null) return;

        Vector3 desiredPosition = target.position + offset;

        // Lerp smoothly moves toward the desired position
        transform.position = Vector3.Lerp(
            transform.position,
            desiredPosition,
            smoothSpeed * Time.deltaTime
        );

        transform.LookAt(target); // Always face the target
    }
}

using UnityEngine;

public class ClickInteract : MonoBehaviour
{
    [SerializeField] private float maxDistance = 50f;
    [SerializeField] private LayerMask interactableLayers;

    void Update()
    {
        if (Input.GetMouseButtonDown(0)) // Left click
        {
            // Create a ray from the camera through the mouse position
            Ray ray = Camera.main.ScreenPointToRay(Input.mousePosition);
            RaycastHit hit;

            if (Physics.Raycast(ray, out hit, maxDistance, interactableLayers))
            {
                Debug.Log("Hit: " + hit.collider.name);
                Debug.DrawLine(ray.origin, hit.point, Color.green, 1f);

                // Try to call an Interact method on the hit object
                IInteractable interactable = hit.collider.GetComponent<IInteractable>();
                interactable?.Interact();
            }
        }
    }
}

