using UnityEngine;
using System;

public class Health : MonoBehaviour
{
    [SerializeField] private float maxHealth = 100f;
    private float currentHealth;

    public event Action OnDeath;           // Fired when health reaches 0
    public event Action<float> OnChanged;  // Fired with normalized 0-1 value

    public float NormalizedHealth => currentHealth / maxHealth;

    void Awake()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(float amount)
    {
        if (currentHealth <= 0) return;  // Already dead

        currentHealth = Mathf.Max(0, currentHealth - amount);
        OnChanged?.Invoke(NormalizedHealth);

        if (currentHealth <= 0)
            OnDeath?.Invoke();
    }

    public void Heal(float amount)
    {
        currentHealth = Mathf.Min(maxHealth, currentHealth + amount);
        OnChanged?.Invoke(NormalizedHealth);
    }
}

