using UnityEngine.SceneManagement;  // Required for scene loading

public class SceneLoader : MonoBehaviour
{
    // --- Synchronous (simple, causes a brief freeze) ---
    public void LoadSceneByName(string sceneName)
    {
        SceneManager.LoadScene(sceneName);
    }

    public void LoadSceneByIndex(int buildIndex)
    {
        SceneManager.LoadScene(buildIndex);
    }

    public void ReloadCurrentScene()
    {
        int current = SceneManager.GetActiveScene().buildIndex;
        SceneManager.LoadScene(current);
    }

    // --- Async (shows loading progress, no freeze) ---
    public void LoadAsync(string sceneName)
    {
        StartCoroutine(LoadAsyncCoroutine(sceneName));
    }

    System.Collections.IEnumerator LoadAsyncCoroutine(string sceneName)
    {
        AsyncOperation op = SceneManager.LoadSceneAsync(sceneName);
        while (!op.isDone)
        {
            float progress = op.progress; // 0-0.9 during load, 1 when done
            Debug.Log("Loading: " + (int)(progress * 100) + "%");
            yield return null;
        }
    }
}

