[RequireComponent(typeof(Animator))]
public class AnimatorController : MonoBehaviour
{
    private Animator anim;
    private Rigidbody rb;

    // Hash string params for performance (avoids string lookup every frame)
    private static readonly int SpeedHash    = Animator.StringToHash("Speed");
    private static readonly int IsGroundedHash = Animator.StringToHash("IsGrounded");
    private static readonly int JumpHash     = Animator.StringToHash("Jump");

    void Awake()
    {
        anim = GetComponent<Animator>();
        rb   = GetComponent<Rigidbody>();
    }

    void Update()
    {
        // Float — drives a Blend Tree for locomotion
        float speed = new Vector3(rb.velocity.x, 0, rb.velocity.z).magnitude;
        anim.SetFloat(SpeedHash, speed);

        // Bool — toggle a state
        bool grounded = IsGrounded();
        anim.SetBool(IsGroundedHash, grounded);

        // Trigger — fires once and auto-resets
        if (Input.GetKeyDown(KeyCode.Space) && grounded)
            anim.SetTrigger(JumpHash);
    }

    bool IsGrounded()
    {
        return Physics.Raycast(transform.position, Vector3.down, 1.1f);
    }
}

using UnityEngine;

/// <summary>
/// Generic Singleton base class for MonoBehaviours.
/// Usage: public class GameManager : Singleton<GameManager> { }
/// Access: GameManager.Instance.DoSomething();
/// </summary>
public class Singleton<T> : MonoBehaviour where T : MonoBehaviour
{
    private static T _instance;

    public static T Instance
    {
        get
        {
            if (_instance == null)
                Debug.LogError(typeof(T) + " instance not found in scene!");
            return _instance;
        }
    }

    protected virtual void Awake()
    {
        if (_instance != null && _instance != this)
        {
            Destroy(gameObject); // Destroy duplicate
            return;
        }
        _instance = this as T;
        DontDestroyOnLoad(gameObject); // Persist across scenes
    }
}

