using UnityEngine;
using System.Collections;

public class EnemySpawner : MonoBehaviour
{
    [SerializeField] private GameObject enemyPrefab;
    [SerializeField] private float spawnInterval = 2f;
    [SerializeField] private int maxEnemies = 10;
    [SerializeField] private float spawnRadius = 10f;

    private int activeEnemies = 0;

    void Start()
    {
        StartCoroutine(SpawnRoutine());
    }

    IEnumerator SpawnRoutine()
    {
        while (true) // Runs indefinitely
        {
            yield return new WaitForSeconds(spawnInterval);

            if (activeEnemies < maxEnemies)
            {
                SpawnEnemy();
            }
        }
    }

    void SpawnEnemy()
    {
        // Random position within a circle around the spawner
        Vector2 randomCircle = Random.insideUnitCircle * spawnRadius;
        Vector3 spawnPos = transform.position + new Vector3(randomCircle.x, 0, randomCircle.y);

        Instantiate(enemyPrefab, spawnPos, Quaternion.identity);
        activeEnemies++;
    }

    // Call this when an enemy dies
    public void OnEnemyDied() => activeEnemies--;
}

using UnityEngine;

public class SimpleEnemyAI : MonoBehaviour
{
    [SerializeField] private Transform player;
    [SerializeField] private float detectionRange = 10f;
    [SerializeField] private float moveSpeed = 3f;
    [SerializeField] private float stopDistance = 1.5f;

    void Update()
    {
        if (player == null) return;

        float distToPlayer = Vector3.Distance(transform.position, player.position);

        if (distToPlayer <= detectionRange)
        {
            // Always face the player (Y-axis only)
            Vector3 dirToPlayer = player.position - transform.position;
            dirToPlayer.y = 0; // Keep enemy upright
            if (dirToPlayer != Vector3.zero)
                transform.rotation = Quaternion.LookRotation(dirToPlayer);

            // Move toward player if not close enough
            if (distToPlayer > stopDistance)
                transform.Translate(Vector3.forward * moveSpeed * Time.deltaTime);
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

public class ObjectPool : MonoBehaviour
{
    [SerializeField] private GameObject prefab;
    [SerializeField] private int poolSize = 20;

    private Queue<GameObject> pool = new Queue<GameObject>();

    void Awake()
    {
        // Pre-warm: create all objects upfront, deactivated
        for (int i = 0; i < poolSize; i++)
        {
            GameObject obj = Instantiate(prefab, transform);
            obj.SetActive(false);
            pool.Enqueue(obj);
        }
    }

    // Get an object from the pool
    public GameObject Get(Vector3 position, Quaternion rotation)
    {
        if (pool.Count == 0)
        {
            // Pool is exhausted — grow it
            GameObject extra = Instantiate(prefab, transform);
            pool.Enqueue(extra);
        }

        GameObject obj = pool.Dequeue();
        obj.transform.SetPositionAndRotation(position, rotation);
        obj.SetActive(true);
        return obj;
    }

    // Return an object to the pool
    public void Return(GameObject obj)
    {
        obj.SetActive(false);
        pool.Enqueue(obj);
    }
}

